"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["50337"],{94843(s){s.exports=JSON.parse('{"tag":{"label":"oauth","permalink":"/sysanalyst-kb.github.io/docs/tags/oauth","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":2,"items":[{"id":"integration/api-auth","title":"\u0410\u0443\u0442\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F \u0438 \u0430\u0432\u0442\u043E\u0440\u0438\u0437\u0430\u0446\u0438\u044F \u0432 API","description":"\u041B\u044E\u0431\u043E\u0439 API, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u043D\u0435 \u0432 \u0438\u0437\u043E\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0439 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u0441\u0435\u0442\u0438, \u043D\u0443\u0436\u0434\u0430\u0435\u0442\u0441\u044F \u0432 \u0437\u0430\u0449\u0438\u0442\u0435. \u0414\u0430\u0436\u0435 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0435 API \u043E\u0431\u044B\u0447\u043D\u043E \u0442\u0440\u0435\u0431\u0443\u044E\u0442 \u0445\u043E\u0442\u044F \u0431\u044B \u0431\u0430\u0437\u043E\u0432\u043E\u0439 \u0430\u0443\u0442\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438, \u0447\u0442\u043E\u0431\u044B \u0437\u043D\u0430\u0442\u044C, \u043A\u0442\u043E \u0438 \u043A\u0430\u043A\u0438\u0435 \u0434\u0430\u043D\u043D\u044B\u0435 \u0437\u0430\u043F\u0440\u0430\u0448\u0438\u0432\u0430\u0435\u0442.","permalink":"/sysanalyst-kb.github.io/docs/integration/api-auth"},{"id":"specialization/govtech-smev","title":"\u0421\u041C\u042D\u0412 \u2014 \u043C\u0435\u0436\u0432\u0435\u0434\u043E\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0435 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435","description":"\u0421\u041C\u042D\u0412 \u2014 \xab\u0448\u0438\u043D\u0430\xbb \u0434\u043B\u044F \u043E\u0431\u043C\u0435\u043D\u0430 \u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u043C\u0435\u0436\u0434\u0443 \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u043C\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438. \u0412\u0435\u0440\u0441\u0438\u044F 3 (\u0442\u0435\u043A\u0443\u0449\u0430\u044F) \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0447\u0435\u0440\u0435\u0437 REST \u0438 JSON (\u0440\u0430\u043D\u0435\u0435 SOAP/XML). \u0427\u0435\u0440\u0435\u0437 \u0421\u041C\u042D\u0412 \u043F\u0440\u043E\u0445\u043E\u0434\u044F\u0442 1B+ \u0437\u0430\u043F\u0440\u043E\u0441\u043E\u0432/\u0433\u043E\u0434, 25 000+ \u043F\u043E\u0434\u043A\u043B\u044E\u0447\u0451\u043D\u043D\u044B\u0445 \u0413\u0418\u0421. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 5-30 \u0441\u0435\u043A), \u044E\u0440\u0438\u0434\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0437\u043D\u0430\u0447\u0438\u043C\u043E\u0441\u0442\u044C (\u0423\u041A\u042D\u041F). \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043F\u0440\u043E\u0432\u0430\u0439\u0434\u0435\u0440\u044B: \u0415\u0421\u0418\u0410 (\u0430\u0443\u0442\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F + \u043C\u0435\u0442\u0430\u0434\u0430\u043D\u043D\u044B\u0435), \u0448\u043B\u044E\u0437 \u0421\u041C\u042D\u0412 (ViPNet, \u043A\u0440\u0438\u043F\u0442\u043E\u0433\u0440\u0430\u0444\u0438\u044F).","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-smev"}],"unlisted":false}}')}}]);